import{_ as i,o as a,c as o,ac as t}from"./chunks/framework.DnBnwVZk.js";const h=JSON.parse('{"title":"Windows修改iTunes备份文件夹路径","description":"","frontmatter":{"date":"2023-11-18T21:58:08.000Z","categories":["技巧"],"tags":["Windows"],"publish":true},"headers":[],"relativePath":"views/skill/windows/ModifyiTunesBackupDirPath.md","filePath":"views/skill/windows/ModifyiTunesBackupDirPath.md","lastUpdated":1775654397000}'),s={name:"views/skill/windows/ModifyiTunesBackupDirPath.md"};function n(l,e,p,d,r,u){return a(),o("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1700344688000"},[...e[0]||(e[0]=[t('<h1 id="windows修改itunes备份文件夹路径" tabindex="-1">Windows修改iTunes备份文件夹路径 <a class="header-anchor" href="#windows修改itunes备份文件夹路径" aria-label="Permalink to &quot;Windows修改iTunes备份文件夹路径&quot;">​</a></h1><p>iTunes默认将iPhone/iPad的备份文件保存在C盘，动辄100G以上的备份对于C盘压力不小，因此希望将备份文件放到数据盘。</p><p>iTunes默认未提供此选项，需要使用Windows的软链接来实现，整体思路参考了<a href="https://zhuanlan.zhihu.com/p/419358584" target="_blank" rel="noreferrer">知乎上的文章</a>,略有变化。</p><ol><li>找到原备份存储目录，截止本文的2023年11月，目录在<code>C:\\Users\\[你的用户名]\\AppData\\Roaming\\Apple Computer\\MobileSync</code>，目录下</li><li>删除上述目录已有的所有文件，或者移动到其他位置待软链接完成后再迁移到新的目录</li><li>新建目标文件夹，如<code>E:\\iPhoneBackuo</code></li><li>建立链接，这里一定要使用cmd(powershell不行)，输入<code>MkLink /J &quot;%AppData%\\Apple Computer\\MobileSync\\Backup&quot; &quot;E:\\iPhoneBackup&quot;</code>，当出现下述提示时表示成功 <ol><li><blockquote><p>为 C:\\Users[username]\\AppData\\Roaming\\Apple Computer\\MobileSync\\Backup &lt;&lt;===&gt;&gt; E:\\iPhoneBackup 创建的联接</p></blockquote></li></ol></li><li>如果第2步有迁移过旧备份文件，则迁移回新的目录</li></ol>',4)])])}const _=i(s,[["render",n]]);export{h as __pageData,_ as default};
